import ProductCard from "./ProductCard"

interface ProductItem {
  id: number;
  title: string;
  price: number;
  image: string
}


const ProductPage = async () => {
  const res = await fetch("https://fakestoreapi.com/products?limit=10")
  const products:ProductItem[] = await res.json(); //product ไปเอาข้อมูลมาจาก array ต้องกำหนด datatype ให้ array ที่ productItem และแปลงค่าเป็น .json
  // console.log(products) //เช็คทุกครั้งเมื่อเรียก API ว่ามีข้อมูลถูกส่งมา





  return (
    <>
      <div className="grid grid-cols-2 mb-cols-3 lg:grid-cols-4 xl:grid-cols-6 gap-4">
        {
          products.map((product:ProductItem) => (
            <ProductCard key = {product.id} product = {product}/> //ต้องไปกำหนด product ที่ส่งไปใน ProductCard ด้วย
          ))
        }
      </div>
    </>
  )
}
export default ProductPage